/**
 * Sets the x and y-coordinates of the bottom left corner
 *
 * @param x The x-coordinate
 * @param y The y-coordinate
 * @return this rectangle for chaining
 */
public RectangleMutant setPosition(float x, float y) {
    this.x = x;
    this.y = y;
    return this;
}
